export type MirrorGatedInsightReason =
  | (typeof MirrorGatedInsightReason)[keyof typeof MirrorGatedInsightReason]
  | null;

export const MirrorGatedInsightReason = {
  need_more_data: "need_more_data",
} as const;

export type MirrorGatedInsightData = { [key: string]: unknown } | null;

/**
 * Wrapper around a trader-mirror insight category. When `gated` is true the cohort was below the minimum sample threshold and `data` is omitted; the UI should render a 'need more data' placeholder.
 */
export interface MirrorGatedInsight {
  gated: boolean;
  reason?: MirrorGatedInsightReason;
  need?: number | null;
  have?: number | null;
  data?: MirrorGatedInsightData;
}

/**
 * Personal trader-mirror insights bundle (task #162). Every category respects a minimum-sample guardrail.
 */
export interface TraderMirrorInsights {
  windowDays: number | null;
  totalResolved: number;
  overallGated: boolean;
  sessions: MirrorGatedInsight;
  instruments: MirrorGatedInsight;
  timing: MirrorGatedInsight;
  postLoss: MirrorGatedInsight;
  exitDiscipline: MirrorGatedInsight;
}

/**
 * Short bilingual one-liner pulled from the insights bundle. Used for both the dashboard hero strip and the weekly trader-report push. `id` is the stable highlight key; `en` and `idText` are the English and Indonesian copy.
 */
export interface TraderMirrorHighlight {
  id: string;
  en: string;
  idText: string;
}

export interface TraderMirrorResponse {
  insights: TraderMirrorInsights;
  highlights: TraderMirrorHighlight[];
  timezone: string;
}

/**
 * Single bucket inside a performance segment (per instrument, FX session, or market-condition). `winRate` is wins / (wins + losses) — only trades that actually triggered. `hitRate` is wins / total resolved (expired included).
 */
export interface PerformanceBucket {
  key: string;
  triggered: number;
  wins: number;
  losses: number;
  expired: number;
  total: number;
  winRate: number | null;
  hitRate: number | null;
}

/**
 * A segmentation of the outcome ledger. `gated` is true when no bucket inside the segment crossed the minimum-sample threshold; the UI then renders a 'need more data' placeholder instead of cherry-picking the largest bucket.
 */
export interface PerformanceSegment {
  gated: boolean;
  need: number;
  have: number;
  buckets: PerformanceBucket[];
}

export interface PerformanceOverall {
  triggered: number;
  wins: number;
  losses: number;
  expired: number;
  total: number;
  winRate: number | null;
  hitRate: number | null;
}

export type PerformanceBannerSeverity =
  (typeof PerformanceBannerSeverity)[keyof typeof PerformanceBannerSeverity];

export const PerformanceBannerSeverity = {
  ok: "ok",
  watch: "watch",
  warn: "warn",
} as const;

/**
 * Honesty banner comparing the last `recentDays` hit-rate against the 30-day baseline. `severity: warn` fires only when recent is >=15pp below baseline AND both windows cleared the minimum-sample guardrail.
 */
export interface PerformanceBanner {
  severity: PerformanceBannerSeverity;
  recentDays: number;
  recentSample: number;
  baselineSample: number;
  recentHitRate: number | null;
  baselineHitRate: number | null;
  delta: number | null;
}

export type PerformanceSummaryWindowDays =
  (typeof PerformanceSummaryWindowDays)[keyof typeof PerformanceSummaryWindowDays];

export const PerformanceSummaryWindowDays = {
  NUMBER_30: 30,
  NUMBER_90: 90,
} as const;

/**
 * Sample-size guardrails the server enforces — published so the UI's honesty copy can quote them directly instead of hardcoding.
 */
export interface PerformanceMinSamples {
  /** Minimum resolved analyses per bucket before that bucket renders. */
  bucket: number;
  /** Minimum resolved analyses overall before any segment renders. */
  overall: number;
  /** Minimum resolved analyses in the recent window before the current-state banner makes a claim. */
  banner: number;
}

/**
 * Public AI transparency snapshot for the rolling `windowDays` window (task #164).
 */
export interface PerformanceSummary {
  windowDays: PerformanceSummaryWindowDays;
  generatedAt: string;
  windowStart: string | null;
  minSamples: PerformanceMinSamples;
  overall: PerformanceOverall;
  banner: PerformanceBanner;
  byInstrument: PerformanceSegment;
  bySession: PerformanceSegment;
  byCondition: PerformanceSegment;
}

/**
 * Anonymised long-vs-short aggregate for an instrument over the last `windowDays`, gated when sample is too small to safely de-identify.
 */
export interface JournalSentiment {
  instrument: string;
  windowDays: number;
  minSampleSize: number;
  minDistinctTraders: number;
  /** Number of directional (buy/sell) entries in the window. Null when `gated` is true (suppressed to prevent membership inference on thin instruments). */
  sampleSize: number | null;
  /** Number of distinct user IDs contributing entries. Null when `gated` is true. */
  distinctTraders: number | null;
  /** True when sample is below thresholds; percentages, sampleSize, and distinctTraders are all null. */
  gated: boolean;
  buyPct: number | null;
  sellPct: number | null;
}

